import{_ as e,c as r,o as i,ag as t}from"./chunks/framework.S-Qvb3wi.js";const p=JSON.parse('{"title":"創世會員計畫概述","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Program-Overview.md","filePath":"zh-TW/Program-Overview.md"}'),o={name:"zh-TW/Program-Overview.md"};function l(d,a,s,n,_,h){return i(),r("div",null,a[0]||(a[0]=[t('<h1 id="創世會員計畫概述" tabindex="-1">創世會員計畫概述 <a class="header-anchor" href="#創世會員計畫概述" aria-label="Permalink to &quot;創世會員計畫概述&quot;">​</a></h1><h2 id="什麼是-dgrid-創世會員" tabindex="-1">什麼是 DGrid 創世會員？ <a class="header-anchor" href="#什麼是-dgrid-創世會員" aria-label="Permalink to &quot;什麼是 DGrid 創世會員？&quot;">​</a></h2><p>DGrid 創世會員是 DGrid 去中心化 AI 生態的核心憑證，更是早期參與者深度綁定網絡的身份象徵。用戶訂閱創世會員服務後，將獲得 Genesis Pass NFT 作為專屬身份憑證；與一般會員權益不同，憑藉該 NFT，創世會員不僅可直接享有高額 AI 資源使用權，更能深度參與網絡發展決策，共享生態成長紅利。</p><p>為維繫網絡長期穩定運營與生態擴張，創世會員只需持續保有會員身份、積極參與生態建設，就能獲得穩定的經濟回饋。對於長期支持生態的持有者而言，後續更有機會領取額外的生態獎勵。本次創世會員計畫特別打造低門檻、平等化的參與機制，讓不同背景的社群成員都能把握去中心化 AI 發展的早期機遇。</p><h2 id="為何要加入創世會員" tabindex="-1">為何要加入創世會員？ <a class="header-anchor" href="#為何要加入創世會員" aria-label="Permalink to &quot;為何要加入創世會員？&quot;">​</a></h2><p>在去中心化 AI 經濟崛起的關鍵階段，成為 DGrid 創世會員，意味著你將從「旁觀者」轉變為「共建者」，為生態帶來多元價值的同時，實現個人與網絡的共贏：</p><ul><li>鞏固去中心化基礎：協助網絡維持去中心化架構，提升對外部風險的抵抗能力，保障生態長期穩定。</li><li>驅動生態規模擴張：透過參與模型部署、基礎設施運營等工作，助力去中心化 AI 推論網絡的版圖拓展。</li><li>普及高質 AI 服務：以實際參與支持網絡運作，讓更多用戶與開發者能低成本獲取高品質 AI 資源。</li><li>領取豐厚回饋獎勵：憑藉對生態的貢獻，獲得 $DGAI 代幣及其他專屬獎勵，共享網絡成長紅利。</li></ul>',7)]))}const m=e(o,[["render",l]]);export{p as __pageData,m as default};
